Complete SPA framework:

class ScreenReaderRouter {
    constructor(routes, containerId) {
        this.routes = routes;
        this.container = document.getElementById(containerId);
        this.liveRegion = document.createElement('div');
        this.liveRegion.setAttribute('aria-live', 'polite');
        this.liveRegion.setAttribute('aria-atomic', 'true');
        this.liveRegion.className = 'sr-only';
        document.body.appendChild(this.liveRegion);

        window.addEventListener('popstate', () => this.render());
    }

    navigate(path) {
        history.pushState(null, '', path);
        this.render();
    }

    async render() {
        const path = location.pathname;
        const route = this.routes.find(r => r.path === path) || this.routes[0];

        // Show loading state
        this.container.innerHTML = '<div role="status" aria-label="Loading">' +
            '<span class="sr-only">Loading page...</span></div>';

        try {
            const html = await route.render();
            this.container.innerHTML = html;

            // Focus management: move focus to main content
            const main = this.container.querySelector('[role="main"], h1, h2');
            if (main) {
                main.setAttribute('tabindex', '-1');
                main.focus();
            }

            // Announce route change
            const title = document.querySelector('h1')?.textContent || route.title;
            document.title = `${title} - My App`;
            this.liveRegion.textContent = `Navigated to ${title}`;
        } catch (err) {
            this.container.innerHTML = '<div role="alert">Failed to load page</div>';
            this.liveRegion.textContent = 'Error loading page';
        }
    }
}

Features:
- Route change announcements via live region
- Focus management to main content
- Loading state with role="status"
- Error state with role="alert"
- Page title updates
- Back/forward browser navigation support
- screen reader-friendly DOM structure
